VALUES
  ('fire-eq-eng-moex-00573', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防法之規定，地面樓層達多少層以上之建築物，其管理權人應使用附有防焰標示之地毯？', '["6層", "11層", "16層", "25層"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00574', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防焰性能試驗基準之規定，下列敘述何者正確？', '["自火源點火接觸試樣起，至火源熄滅之時間，稱為點火時間", "自火源點火接觸試樣起，至試樣停止 燃燒之時間，稱為餘焰時間", "自點火時間終了起，至試樣停止燃燒之時間，稱為餘燃時間", "試樣經 加熱燃燒後碳化部分之最大長度，稱為碳化距離"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00575', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法之規定，有關類別及場所定義，下列敘述何 者正確？', '["可燃性高壓氣體包括在攝氏15度時，表壓力達每平方公分2公斤以上之液化石油氣", "室內儲槽場所及室外儲槽場所之儲槽，其設置容量為超過600公升，且不可移動之儲槽", "販賣裝於容器之六類物品，其數量達管制量15倍以上，未達30倍之場所，稱為第二種販賣場所", "閃火點在攝氏200度以上之第四類公共危險物品，稱為高閃火點物品"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00576', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法之規定，有關六類物品製造場所之設置位 置，下列敘述何者正確？', '["製造場所與廠區外之戲院、電影院之安全距離應在50公尺以上", "製造場所設有擋牆防護與廠區外之古蹟之安全距離應在25公尺以上", "儲存量達管制量10倍以上者，四周保留空地寬度應在3公尺以上", "因作業流程具有連接性，設有高於屋頂，為不燃材料建造且具 2 小時以上防火時效之防火牆者，其四 周保留空地寬度得減半計算"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00577', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '甲乙丙三家瓦斯行設有容器儲存室，其儲存面積分別為 6、16、30 平方公尺，容器儲存室與場外第一類 保護物之法定安全距離分別為X、Y、Z公尺，請問X、Y、Z為多少？', '["8.4、12.0、22.5", "8.4、12.0、15.0", "12.6、12.0、15.0", "12.6、18.0、22.5"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00578', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依滅火器認可基準之規定，有關滅火器重量（不含固定掛鉤、背負帶或輪架之重量）在X kg以下者應為 手提式或背負式，超過Y kg以上者應為輪架方式。請問X、Y為多少？', '["X：15 kg，Y：25 kg", "X：18 kg，Y：25 kg", "X：18 kg，Y：28 kg", "X：28 kg，Y：35 kg"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00579', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防火牆及防火水幕設置基準之規定，有關防火水幕設備設置，下列敘述何者正確？', '["加壓送水裝置啟動後3分鐘內應能形成水幕", "防護之儲槽容量達一萬公秉以上者，其緊急電源供電容量時間為180分鐘", "防護之儲槽容量未達一萬公秉者，其水源容量不得小於防護該儲槽連續放水120分鐘之水量", "防火水幕之水源不得與其他滅火設備水源併設"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00580', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依一齊開放閥認可基準之規定，下列敘述何者錯誤？', '["本基準適用於消防用自動撒水設備、水霧滅火設備及自動泡沫滅火設備等所使用之一齊開放閥", "依據控制部之構造可分為加壓型、減壓型、電動型、電磁型等四種", "控制部動作後15秒內開啟出水；但內徑超過200 mm者，則需於60秒內開啟出水", "利用壓力進行開啟之控制部，施以規定之壓力值試驗5分鐘後，不得有漏水、變形等破壞之情形產生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00581', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依可燃性高壓氣體儲存場所防護牆設置基準之規定，有關防護牆之設置，下列敘述何者正確？', '["防護牆種類雖有不同，惟其高度均應為2公尺以上", "鋼筋混凝土製防護牆之厚度應為12公分以上", "鋼板製A防護牆之厚度應為9公分以上", "鋼筋混凝土經過28日養生後之抗壓強度應為140 kgf/cm2以上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00582', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準之規定，有關高度及中度危險工作場所之定義，下列敘述何者錯誤？', '["儲存一般可燃性固體物質倉庫之高度未超過5.5公尺之場所，可稱為中度危險工作場所", "儲存易燃性液體物質之閃火點超過攝氏60度之作業場所，可稱為中度危險工作場所", "儲存一般可燃性固體物質倉庫之高度超過5.5公尺之場所，可稱為高度危險工作場所", "儲存易燃性液體物質之閃火點未超過攝氏60度與攝氏溫度為37.8度時，其蒸氣壓未超過每平方公分3 公斤之場所，可稱為高度危險工作場所"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
